measures.expression:
CALCULATE(
    [Total Customers],
    KEEPFILTERS(
        'Customer Activity Status Monthly'[Dim Customer Activity Status Sk]
            IN { "Reactive", "Exist", "New" }
    )
)

CALCULATE(
    [Total Customers],
    KEEPFILTERS(
        'Customer Activity Status Yearly'[Dim Customer Activity Status Sk] <> "Churn"
    )
)
